SELECT bs.bldg_id, bs.applicability, up.applicability AS applicability_1 FROM resstock_2024_amy2018_release_2_metadata AS bs JOIN resstock_2024_amy2018_release_2_metadata AS up ON bs.bldg_id = up.bldg_id AND bs.upgrade = 0 WHERE bs.applicability = true AND bs.upgrade = 0 AND up.applicability = true AND up.upgrade = 1 AND (bs."out.electricity.total.energy_consumption" - up."out.electricity.total.energy_consumption" >= 0.001 OR bs."out.natural_gas.total.energy_consumption" - up."out.natural_gas.total.energy_consumption" >= 0.001 OR bs."out.fuel_oil.total.energy_consumption" - up."out.fuel_oil.total.energy_consumption" >= 0.001 OR bs."out.propane.total.energy_consumption" - up."out.propane.total.energy_consumption" >= 0.001)